INSERT INTO package_settings VALUES(1,'Our Packages','Premium photography packages designed to capture your most important moments with cinematic excellence.','View All Packages','/packages',1782397277);
INSERT INTO packages VALUES(1,'Wedding Essential','wedding-essential','wedding','Perfect for intimate ceremonies','Capture every precious moment of your intimate wedding ceremony. This package includes professional coverage of the ceremony, couple portraits, and family group photos with expertly edited deliverables.','["4-6 hours coverage","1 photographer","200+ edited photos","Online gallery","10 printed photos (8x12)","Highlight slideshow"]',35000.0,'Starting from','BDT','4-6 hours','200+ edited photos',0,1,'/uploads/packages/1-1782398220200.jpg',0,1782397277,1782398220);
INSERT INTO packages VALUES(2,'Wedding Premium','wedding-premium','wedding','Complete coverage for your big day','Full-day wedding coverage with a team of photographers ensuring no moment goes uncaptured. From getting ready shots to the reception, every emotion and detail is documented beautifully.','["Full day coverage (12+ hours)","2 photographers","500+ edited photos","Cinematic highlight video (3-5 min)","Premium album (40 pages)","Online gallery","Pre-wedding shoot included","Drone coverage"]',85000.0,'Starting from','BDT','Full day (12+ hours)','500+ edited photos + video',1,1,NULL,1,1782397277,1782397277);
INSERT INTO packages VALUES(3,'Corporate Event','corporate-event','corporate','Professional event documentation','Professional photography for corporate events, conferences, seminars, and product launches. Clean, sharp images perfect for press releases, social media, and internal communications.','["4-8 hours coverage","1-2 photographers","300+ edited photos","Same-day preview (20 photos)","Corporate headshots (up to 20 people)","Event highlight video","Social media ready crops"]',45000.0,'Starting from','BDT','4-8 hours','300+ edited photos',0,1,NULL,2,1782397277,1782397277);
INSERT INTO packages VALUES(4,'Fashion Portfolio','fashion-portfolio','fashion','Elevate your fashion brand','High-end fashion photography for lookbooks, campaigns, and portfolios. Studio or location shoots with professional lighting and creative direction to showcase your designs.','["Half day studio/location shoot","Professional lighting setup","50+ edited photos","5 retouched hero images","Mood board consultation","Styling guidance","Commercial usage license"]',55000.0,'Starting from','BDT','Half day (4-5 hours)','50+ edited photos',1,1,NULL,3,1782397277,1782397277);
INSERT INTO packages VALUES(5,'Product Photography','product-photography','product','Make your products shine','Clean, professional product photography for e-commerce, catalogs, and advertising. White background, lifestyle, and creative compositions that make your products irresistible.','["Up to 20 products","White background shots","Lifestyle compositions","Multiple angles per product","Web-optimized exports","E-commerce ready","2-day turnaround"]',25000.0,'Starting from','BDT','1 day','60+ product photos',0,1,NULL,4,1782397277,1782397277);
INSERT INTO packages VALUES(6,'Event Coverage','event-coverage','event','Document your special occasions','Whether it''s a birthday celebration, anniversary, or community gathering, we capture the energy, joy, and candid moments that make your event memorable.','["3-5 hours coverage","1 photographer","150+ edited photos","Online gallery","Quick turnaround (5 days)","Social media highlights"]',20000.0,'Starting from','BDT','3-5 hours','150+ edited photos',1,1,NULL,5,1782397277,1782397277);
