INSERT INTO projects VALUES(1,'Urban Elegance — Fashion Editorial','urban-elegance-fashion','A high-fashion editorial shoot blending modern urban architecture with luxury couture styling and cinematic lighting.','["This editorial was conceived as a dialogue between structure and softness — sharp city lines meeting fluid fabric and deliberate poses.","Shot across three locations in Dhaka''s modern business district, each frame was lit to emphasise texture, silhouette, and the interplay of warm amber tones against cool concrete.","The result is a portfolio of images that feel both editorial and timeless — crafted for a luxury fashion brand seeking a modern urban identity."]','2025-09-15','Luxe Atelier',1,'/uploads/projects/costly-buyer-mistakes-1782480813222.jpg','Fashion editorial photography — urban elegance',1,'Urban Elegance Fashion Editorial | PixelRoot Studio','High-fashion editorial photography blending urban architecture with luxury couture styling.',0,1782397277,1782480816);
INSERT INTO projects VALUES(2,'Garden Romance — Wedding Collection','garden-romance-wedding','An intimate garden wedding captured with documentary sensitivity and cinematic colour grading for timeless keepsakes.','["From the first look beneath the banyan trees to the final dance under string lights, every moment of this celebration was documented with an unobtrusive, story-driven approach.","We prioritised authentic emotion over posed perfection — allowing the couple''s natural connection to guide the narrative of the day.","The final gallery delivers a cohesive visual story: warm, romantic, and designed to be treasured for generations."]','2025-06-22','Rahman & Sultana',1,'https://images.unsplash.com/photo-1519741497674-611481863552?w=1200&q=85&auto=format&fit=crop','Wedding photography — garden ceremony',2,'Garden Romance Wedding | PixelRoot Studio','Intimate garden wedding photography with documentary sensitivity and cinematic colour.',1,1782397277,1782397277);
INSERT INTO projects VALUES(3,'Summit Corporate — Brand Campaign','summit-corporate-brand','A corporate brand photography campaign for a leading technology firm, showcasing leadership, culture, and workplace excellence.','["Summit Technologies needed a visual identity refresh for their annual report, website, and social channels — imagery that communicates innovation, trust, and human connection.","Over two days on location, we photographed executive portraits, team collaborations, and candid workplace moments using a clean, modern lighting setup.","The delivered assets gave the brand a cohesive, premium visual language across all touchpoints."]','2025-03-10','Summit Technologies',0,'https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=1200&q=85&auto=format&fit=crop','Corporate brand photography',3,'Summit Corporate Brand Campaign | PixelRoot Studio','Corporate brand photography showcasing leadership, culture, and workplace excellence.',2,1782397277,1782397277);
INSERT INTO projects VALUES(4,'Artisan Collection — Product Photography','artisan-product-collection','Commercial product photography for a luxury skincare line, featuring meticulous lighting and refined post-production.','["Each product in the Artisan Skincare line was photographed individually with a consistent lighting rig designed to highlight glass textures, label typography, and liquid clarity.","Multiple angles and lifestyle compositions were created for e-commerce, packaging, and digital advertising use.","Post-production focused on colour accuracy and subtle enhancement — ensuring the products looked as premium in print as they do in person."]','2024-11-05','Artisan Skincare Co.',0,'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=1200&q=85&auto=format&fit=crop','Commercial product photography',5,'Artisan Product Collection | PixelRoot Studio','Luxury skincare product photography with meticulous lighting and refined post-production.',3,1782397277,1782397277);
INSERT INTO site_settings VALUES(1,'PixelRoot Studio','https://example.com','PixelRoot Studio | Professional Photography Services','PixelRoot Studio offers professional photography for weddings, portraits, events, and commercial projects.','en_US','@pixelrootstudio','["photography","wedding photography","portrait photography","event photography","professional photographer"]','PixelRoot Studio','hello@example.com','+8801000000000','','','','','','','','/uploads/brand/1-1782481749545.jpg',1782481755,'/uploads/brand/screenshot-at-feb-17-15-41-11-1782481687026.png','/uploads/brand/screenshot-at-feb-17-15-41-11-1782481672988.png');
INSERT INTO team_members VALUES(1,'Md Shariful Haque Hira','Founder & Lead Photographer','With 15+ years across fashion, weddings, corporate and commercial photography, Shariful leads every major project with precision, artistry and uncompromising quality.','https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=600&q=85&auto=format&fit=crop&crop=faces',1,0,1782397277);
INSERT INTO team_members VALUES(2,'Arif Rahman','Senior Photographer','Specialising in wedding and portrait photography, Arif brings a sensitive documentary-style eye that captures raw, authentic emotion in every frame.','https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=600&q=85&auto=format&fit=crop&crop=faces',0,1,1782397277);
INSERT INTO team_members VALUES(3,'Nadia Islam','Cinematographer & Video Director','Nadia crafts cinematic event films and brand videos with a narrative-first approach and a signature warm, polished visual tone.','https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=600&q=85&auto=format&fit=crop&crop=faces',0,2,1782397277);
INSERT INTO team_members VALUES(4,'Tanvir Ahmed','Post-Production Lead','Tanvir oversees all colour grading and retouching, ensuring every delivered image meets PixelRoot Studio''s meticulous quality benchmark.','https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=600&q=85&auto=format&fit=crop&crop=faces',0,3,1782397277);
